// PersonalAIMentor.jsx
import React, { useEffect, useState, useRef, useContext } from "react";
import { AuthContext } from "../context/AuthContext";
import "./PersonalAIMentor.css";

const firstMessages = {
  INTP: "გამარჯობა 😊 მოდი ერთად გავაანალიზოთ შენი ძლიერი მხარეები.",
  ENFP: "გამარჯობა 🌟 როგორ შემიძლია დაგეხმარო უკეთ გაიცნო შენი შესაძლებლობები?",
  ESFJ: "გამარჯობა 💛 გინდა ვისაუბროთ შენს ურთიერთობებზე და მიზნებზე?",
  ENTP: "გამარჯობა 💡 მოდი ვიფიქროთ კრეატიულად შენს იდეებზე!",
  DEFAULT: "გამარჯობა 😊 როგორ შემიძლია დაგეხმარო?"
};

const proactiveQuestions = {
  INTJ: "რა გრძელვადიან მიზანზე ფიქრობ ახლა?",
  INTP: "რა იდეა გაწუხებს ბოლო დროს?",
  ENTJ: "რომელი მიზნის მიღწევა გინდა ყველაზე სწრაფად?",
  ENTP: "რა ახალი იდეა გაქვს?",
  INFJ: "რა თემაზე გინდა ღრმად ფიქრი?",
  INFP: "რა გაძლევს შთაგონებას ახლა?",
  ENFJ: "ვის დახმარებას ცდილობ ამ პერიოდში?",
  ENFP: "რა გინდა სცადო ახალი?",
  ISTJ: "რა გეგმაზე მუშაობ ახლა?",
  ISFJ: "რა გინდა გააუმჯობესო ყოველდღიურობაში?",
  ESTJ: "რა ამოცანა უნდა გადაწყვიტო?",
  ESFJ: "როგორ მიდის შენი ურთიერთობები?",
  ISTP: "რა პრობლემის გადაჭრას ცდილობ?",
  ISFP: "რა გაძლევს სიმშვიდეს?",
  ESTP: "რა მოქმედებაზე ფიქრობ?",
  ESFP: "რა საინტერესო მოხდა დღეს?"
};
export default function PersonalAIMentor({ userType, memory }) {
  const { user } = useContext(AuthContext);

  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [currentMBTI, setCurrentMBTI] = useState(userType || "DEFAULT");

  const messagesEndRef = useRef(null);
  const textareaRef = useRef(null);
  const firstLoad = useRef(true);

  const token = user?.token || localStorage.getItem("auth_token");
  const safeUserId = user?._id;

  // ================= SCROLL =================
  const scrollToBottom = () => {
    const container = messagesEndRef.current?.parentElement;
    if (!container) return;
    container.scrollTop = container.scrollHeight;
  };

  // ================= FETCH HISTORY =================
  useEffect(() => {
    if (!safeUserId || !token) return;

    const fetchHistory = async () => {
      try {
        const res = await fetch(`http://localhost:5000/api/chat-reply/history`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        if (!res.ok) throw new Error("History fetch failed");

        const data = await res.json();
        const history = data.history || [];

        if (!history.length) {
          const greeting = firstMessages[currentMBTI] || firstMessages.DEFAULT;
          const proactive = proactiveQuestions[currentMBTI] || "როგორ მიდის დღე?";
          setMessages([{ role: "ai", text: greeting + " " + proactive }]);
          setMessages([{ role: "ai", text: greeting }]);
        } else {
          setMessages(history.map(m => ({ role: m.role, text: m.text })));

          const lastMBTI = history[history.length - 1]?.mbtiType;
          if (lastMBTI && lastMBTI !== "Unknown") setCurrentMBTI(lastMBTI);
        }
      } catch (err) {
        console.error("History error:", err);
        const greeting = firstMessages[currentMBTI] || firstMessages.DEFAULT;
        setMessages([{ role: "ai", text: greeting }]);
      }
    };

    fetchHistory();
  }, [safeUserId, token, currentMBTI]);

  // ================= SYNC WITH userType PROP =================
  useEffect(() => {
    if (userType && userType !== currentMBTI) {
      setCurrentMBTI(userType);
    }
  }, [userType, currentMBTI]);

  // ================= AUTO SCROLL =================
  useEffect(() => {
    if (firstLoad.current) {
      firstLoad.current = false;
      return;
    }
    scrollToBottom();
  }, [messages]);

  if (!safeUserId) return <div className="ai-mentor">გთხოვ გაიარე ავტორიზაცია 😊</div>;

  // ================= SEND MESSAGE =================
  const sendMessage = async () => {
    if (!input.trim() || loading) return;

    const text = input;
    setInput("");
    if (textareaRef.current) textareaRef.current.style.height = "auto";

    setMessages(prev => [...prev, { role: "user", text }]);
    setLoading(true);

    try {
      const res = await fetch("http://localhost:5000/api/chat-reply", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({
          message: text,
          type: currentMBTI,
          newChat: false,
          memory: memory || {}
        })
      });

      if (!res.ok) throw new Error("Chat failed");
      const data = await res.json();

      setMessages(prev => [...prev, { role: "ai", text: data.reply }]);
      if (data.mbtiType && data.mbtiType !== "Unknown") setCurrentMBTI(data.mbtiType);

      scrollToBottom();
    } catch (err) {
      console.error("Send error:", err);
      setMessages(prev => [...prev, { role: "ai", text: "😔 ჩატი დროებით მიუწვდომელია" }]);
    }

    setLoading(false);
  };

  // ================= NEW CHAT =================
  const newChat = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/chat-reply", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({
          message: "ახალი ჩატი დაიწყო",
          type: currentMBTI,
          newChat: true,
          memory: memory || {}
        })
      });

      const data = await res.json();

      const firstMsg = data.reply || firstMessages[currentMBTI] || firstMessages.DEFAULT;
      setMessages([{ role: "ai", text: firstMsg }]);

      if (data.mbtiType && data.mbtiType !== "Unknown") setCurrentMBTI(data.mbtiType);
      scrollToBottom();
      textareaRef.current?.focus();
    } catch (err) {
      console.error("New chat error:", err);
    }
  };

  return (
    <div className="ai-mentor">
      <div className="ai-header">
        Personal AI Mentor ({currentMBTI})
        <button className="new-chat-btn" onClick={newChat}>New Chat</button>
      </div>

      <div className="ai-messages">
        {messages.map((m, i) => <div key={i} className={`msg ${m.role}`}>{m.text}</div>)}
        {loading && <div className="msg ai">AI წერს...</div>}
        <div ref={messagesEndRef}></div>
      </div>

      <div className="ai-input">
        <textarea
          ref={textareaRef}
          value={input}
          rows="1"
          placeholder="მომწერე..."
          onChange={(e) => {
            const el = e.target;
            setInput(el.value);
            el.style.height = "auto";
            el.style.height = Math.min(el.scrollHeight, 90) + "px";
          }}
          onKeyDown={(e) => {
            if (e.key === "Enter" && !e.shiftKey) {
              e.preventDefault();
              sendMessage();
            }
          }}
        />
        <button onClick={sendMessage} disabled={loading}>გაგზავნა</button>
      </div>
    </div>
  );
}
